from dash import Input, Output, html, no_update
from plotly.subplots import make_subplots
import plotly.graph_objects as go
import gui_graphs as gg


def data_to_figure(app, graph, left_axis, right_axis):
    @app.callback(
        Output(graph, "figure"), 
        Input("graph_data_store", "data"),
        prevent_initial_call=True
    )
    def dtf(data):
        figure = make_subplots(specs=[[{"secondary_y": True}]])
        # Linke Y-Achse
        figure.add_trace(
            go.Scatter(x=data["clock_time"], y=data[left_axis],
                    name="Temperatur", mode="markers+lines"),
            secondary_y=False,
        )
        # Rechte Y-Achse
        figure.add_trace(
            go.Scatter(x=data["clock_time"], y=data[right_axis],
                    name="Druck", mode="markers+lines"),
            secondary_y=True,
        )
        # Achsenbeschriftungen
        figure.update_yaxes(title_text=left_axis, secondary_y=False)
        figure.update_yaxes(title_text=right_axis, secondary_y=True)
        figure.update_xaxes(tickformat='%H:%M:%S')
        figure = gg.update_graph_layout(figure)
        return figure

# DICT AUS DEM FRONTEND KOPPIEREN UND HIER MAL TESTWEISE EINBAUEN


def create_graph_callbacks(app):
    return(html.Div([
        data_to_figure(app, 'ph_graph', 'art_ph', 'ven_ph'),
    ]))

